class Solution {
    public List<Integer> findAllPeople(int n, int[][] meetings, int firstPerson) {
        UnionFind uf = new UnionFind(n);
        uf.union(0, firstPerson);
        Arrays.sort(meetings, (a, b) -> a[2] - b[2]);
        int time = 0;
        for (int i = 0; i < meetings.length; i++) {
            if (meetings[i][2] != time) {
                uf.reset();
                time = meetings[i][2];
            }
            uf.union(meetings[i][0], meetings[i][1]);
        }
        List<Integer> res = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if (uf.find(i) == uf.find(0)) {
                res.add(i);
            }
        }
        return res;
    }

    class UnionFind {
        int[] parent;
        boolean[] hasSecret;

        public UnionFind(int n) {
            parent = new int[n];
            hasSecret = new boolean[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
            hasSecret[0] = true;
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                parent[rootX] = rootY;
                hasSecret[rootY] = hasSecret[rootX] || hasSecret[rootY];
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void reset() {
            for (int i = 0; i < parent.length; i++) {
                if (hasSecret[i]) {
                    parent[i] = i;
                }
            }
        }
    }
}
